"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[2256],{7674(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/intro","label":"Visi\xf3n General del Proyecto","docId":"intro","unlisted":false},{"type":"category","label":"Documentaci\xf3n T\xe9cnica","items":[{"type":"link","href":"/docs/tecnico/arquitectura-contexto","label":"01. Arquitectura y Contexto C4","docId":"tecnico/arquitectura-contexto","unlisted":false},{"type":"link","href":"/docs/tecnico/detalle-frontend","label":"02. Detalle de Frontend React","docId":"tecnico/detalle-frontend","unlisted":false},{"type":"link","href":"/docs/tecnico/mapeo-paginas-jsx","label":"03. Mapeo de Componentes .jsx","docId":"tecnico/mapeo-paginas-jsx","unlisted":false},{"type":"link","href":"/docs/tecnico/detalle-backend","label":"04. Detalle de Backend FastAPI","docId":"tecnico/detalle-backend","unlisted":false},{"type":"link","href":"/docs/tecnico/base-datos-seguridad","label":"05. Base de Datos y Seguridad","docId":"tecnico/base-datos-seguridad","unlisted":false}],"collapsed":true,"collapsible":true,"href":"/docs/category/documentaci\xf3n-t\xe9cnica"},{"type":"category","label":"Manual de Usuario","items":[{"type":"link","href":"/docs/usuario/introduccion-guia","label":"01. Introducci\xf3n y Gu\xeda","docId":"usuario/introduccion-guia","unlisted":false},{"type":"link","href":"/docs/usuario/roles-permisos","label":"02. Roles y Privilegios","docId":"usuario/roles-permisos","unlisted":false},{"type":"link","href":"/docs/usuario/flujo-miembro-embajador","label":"03. Miembro y Embajador","docId":"usuario/flujo-miembro-embajador","unlisted":false},{"type":"link","href":"/docs/usuario/flujo-soporte-organizador","label":"04. Soporte y Organizador","docId":"usuario/flujo-soporte-organizador","unlisted":false},{"type":"link","href":"/docs/usuario/flujo-administrador","label":"05. Consola del Administrador","docId":"usuario/flujo-administrador","unlisted":false}],"collapsed":true,"collapsible":true,"href":"/docs/category/manual-de-usuario"}]},"docs":{"intro":{"id":"intro","title":"Visi\xf3n General del Proyecto","description":"Bienvenidos a la documentaci\xf3n centralizada de la Plataforma MEH. Este ecosistema digital ha sido dise\xf1ado como una soluci\xf3n de ingenier\xeda de software de alta disponibilidad para la gobernanza y dinamizaci\xf3n de comunidades tecnol\xf3gicas de vanguardia.","sidebar":"tutorialSidebar"},"tecnico/arquitectura-contexto":{"id":"tecnico/arquitectura-contexto","title":"Arquitectura y Contexto de la Plataforma","description":"La Plataforma MEH (Microsoft Education Hub) es un sistema integral e interactivo dise\xf1ado para la gesti\xf3n de comunidades tecnol\xf3gicas, control de eventos por checkpoints QR, aula virtual (LMS), gamificaci\xf3n con insignias y conciliaci\xf3n autom\xe1tica de pagos utilizando procesamiento OCR.","sidebar":"tutorialSidebar"},"tecnico/base-datos-seguridad":{"id":"tecnico/base-datos-seguridad","title":"Base de Datos Relacional y Protocolos de Seguridad","description":"La base de datos relacional PostgreSQL de la Plataforma MEH representa el n\xfacleo persistente y transaccional del sistema. Est\xe1 gobernada mediante SQLAlchemy s\xedncrono y migrada secuencialmente utilizando Alembic a trav\xe9s de un historial unificado de 11 revisiones de migraci\xf3n.","sidebar":"tutorialSidebar"},"tecnico/detalle-backend":{"id":"tecnico/detalle-backend","title":"Arquitectura Interna del Backend","description":"El backend de la Plataforma MEH est\xe1 desarrollado como un servidor de API RESTful estructurado en FastAPI ejecut\xe1ndose bajo Python 3.11. La arquitectura prioriza el rendimiento s\xedncrono puro y la robustez transaccional, evitando el uso excesivo de llamadas as\xedncronas no bloqueantes que puedan inducir a fallas de concurrencia e hilos a nivel de ORM.","sidebar":"tutorialSidebar"},"tecnico/detalle-frontend":{"id":"tecnico/detalle-frontend","title":"Arquitectura Interna del Frontend","description":"El frontend de la Plataforma MEH est\xe1 dise\xf1ado como una Single Page Application (SPA) de alto rendimiento que se ejecuta del lado del cliente. Se ha implementado utilizando React 18 con JSX est\xe1ndar (sin TypeScript) y el sistema de empaquetado ultra-r\xe1pido Vite, maximizando la velocidad de compilaci\xf3n y optimizando los tiempos de recarga en caliente del navegador (HMR).","sidebar":"tutorialSidebar"},"tecnico/mapeo-paginas-jsx":{"id":"tecnico/mapeo-paginas-jsx","title":"Mapeo de Componentes Frontend .jsx a la API Backend","description":"El frontend interact\xfaa con el backend de FastAPI de forma s\xedncrona mediante llamadas HTTP de Axios. A continuaci\xf3n se desglosa el mapeo f\xedsico formal de las 23 p\xe1ginas principales y los 9 componentes l\xf3gicos administrativos de la carpeta Admin/ con sus respectivos archivos controladores (routers) y servicios en el backend, indicando las tablas relacionales afectadas y el flujo transaccional.","sidebar":"tutorialSidebar"},"usuario/flujo-administrador":{"id":"usuario/flujo-administrador","title":"Consola de Administraci\xf3n y Control Financiero OCR","description":"Este documento describe la funcionalidad integral, las herramientas transaccionales de control de fraude, los motores de automatizaci\xf3n de visi\xf3n artificial y la emisi\xf3n criptogr\xe1fica disponibles de manera exclusiva en la Consola del Administrador de la Plataforma MEH.","sidebar":"tutorialSidebar"},"usuario/flujo-miembro-embajador":{"id":"usuario/flujo-miembro-embajador","title":"Flujo del Estudiante y Biblioteca VIP del Embajador","description":"Este documento detalla las directrices funcionales, flujos de procesos y gu\xedas interactivas paso a paso para los roles de Miembro (estudiante de la comunidad) y Embajador (l\xedder t\xe9cnico/ponente). Ambos roles constituyen la base acad\xe9mica y el n\xfacleo de crecimiento de la Plataforma MEH (Microsoft Education Hub).","sidebar":"tutorialSidebar"},"usuario/flujo-soporte-organizador":{"id":"usuario/flujo-soporte-organizador","title":"Flujo de Soporte Log\xedstico y Organizador de Eventos","description":"Este documento detalla las directrices operativas y de control de los roles de Soporte (encargado de log\xedstica f\xedsica) y Organizador (docente o coordinador de eventos). Ambos roles posibilitan la ejecuci\xf3n exitosa de las actividades presenciales, s\xedncronas e h\xedbridas de la Plataforma MEH (Microsoft Education Hub).","sidebar":"tutorialSidebar"},"usuario/introduccion-guia":{"id":"usuario/introduccion-guia","title":"Introducci\xf3n y Gu\xeda de Primeros Pasos","description":"Bienvenido a la gu\xeda oficial de usuario de la Plataforma MEH (Microsoft Education Hub). Este manual est\xe1 dise\xf1ado para orientarte paso a paso en el uso de la suite interactiva de la comunidad.","sidebar":"tutorialSidebar"},"usuario/roles-permisos":{"id":"usuario/roles-permisos","title":"Matriz de Control de Acceso por Roles (RBAC)","description":"Para garantizar la seguridad, la confidencialidad de la informaci\xf3n financiera y el orden log\xedstico en las capacitaciones, la Plataforma MEH implementa un modelo jer\xe1rquico de Control de Acceso Basado en Roles (RBAC).","sidebar":"tutorialSidebar"}}}}')}}]);